import{_ as s,o as a,c as n,ag as i}from"./chunks/framework.DGzMGr_a.js";const c=JSON.parse('{"title":"ISO 9001:2015 质量管理体系","description":"","frontmatter":{},"headers":[],"relativePath":"standards/index.md","filePath":"standards/index.md","lastUpdated":null}'),d={name:"standards/index.md"};function r(e,t,l,o,h,p){return a(),n("div",null,[...t[0]||(t[0]=[i(`<h1 id="iso-9001-2015-质量管理体系" tabindex="-1">ISO 9001:2015 质量管理体系 <a class="header-anchor" href="#iso-9001-2015-质量管理体系" aria-label="Permalink to &quot;ISO 9001:2015 质量管理体系&quot;">​</a></h1><p>ISO 9001:2015 是国际标准化组织（ISO）发布的质量管理体系（QMS）标准，适用于任何行业和规模的组织。它是全球应用最广泛的质量管理标准。</p><h2 id="七大质量管理原则" tabindex="-1">七大质量管理原则 <a class="header-anchor" href="#七大质量管理原则" aria-label="Permalink to &quot;七大质量管理原则&quot;">​</a></h2><p>ISO 9001:2015 建立在以下七项质量管理原则之上：</p><table tabindex="0"><thead><tr><th>原则</th><th>说明</th></tr></thead><tbody><tr><td><strong>1. 以顾客为关注焦点</strong></td><td>组织应理解并满足顾客当前和未来的需求，超越顾客期望。</td></tr><tr><td><strong>2. 领导作用</strong></td><td>各级领导者应建立统一的质量方针和质量目标，营造良好的内部环境。</td></tr><tr><td><strong>3. 全员参与</strong></td><td>全员胜任、授权并积极参与，是实现质量目标的关键。</td></tr><tr><td><strong>4. 过程方法</strong></td><td>将活动作为相互关联的过程来管理，有助于高效实现预期输出。</td></tr><tr><td><strong>5. 改进</strong></td><td>持续改进是组织保持绩效的必要条件。</td></tr><tr><td><strong>6. 循证决策</strong></td><td>基于数据和信息的分析进行决策，更加客观、可靠。</td></tr><tr><td><strong>7. 关系管理</strong></td><td>与供方等相关方建立互利关系，提升创造价值的能力。</td></tr></tbody></table><h2 id="pdca-循环" tabindex="-1">PDCA 循环 <a class="header-anchor" href="#pdca-循环" aria-label="Permalink to &quot;PDCA 循环&quot;">​</a></h2><p>ISO 9001:2015 采用 <strong>PDCA 循环</strong>（Plan-Do-Check-Act）作为过程方法的核心框架：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    P[Plan 策划] --&gt; D[Do 实施]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; C[Check 检查]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; A[Act 改进]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A --&gt; P</span></span></code></pre></div><ul><li><strong>Plan（策划）</strong>：设定质量目标，识别风险和机遇，制定过程和控制措施。</li><li><strong>Do（实施）</strong>：按照计划执行过程。</li><li><strong>Check（检查）</strong>：监视和测量过程及产品，对照方针、目标和要求报告结果。</li><li><strong>Act（改进）</strong>：采取措施持续改进过程绩效。</li></ul><h2 id="基于风险的思维" tabindex="-1">基于风险的思维 <a class="header-anchor" href="#基于风险的思维" aria-label="Permalink to &quot;基于风险的思维&quot;">​</a></h2><p>ISO 9001:2015 引入了 <strong>基于风险的思维</strong>（Risk-Based Thinking），取代了预防措施的单独条款：</p><ul><li>风险不一定是负面的——机遇也被视为一种风险。</li><li>组织应识别影响 QMS 目标达成的风险和机遇。</li><li>策划质量体系时，需制定应对风险和利用机遇的措施。</li><li>风险分析可以简单（如头脑风暴）或复杂（如 FMEA），视组织环境而定。</li></ul><h2 id="条款-0–10-章节结构" tabindex="-1">条款 0–10 章节结构 <a class="header-anchor" href="#条款-0–10-章节结构" aria-label="Permalink to &quot;条款 0–10 章节结构&quot;">​</a></h2><p>ISO 9001:2015 采用 <strong>HLS（High-Level Structure）</strong> 高阶架构，共 10 个条款：</p><table tabindex="0"><thead><tr><th>条款</th><th>标题</th><th>内容概要</th></tr></thead><tbody><tr><td>0–3</td><td>引言、范围、引用标准、术语</td><td>标准基础信息</td></tr><tr><td><strong>4</strong></td><td><strong>组织环境</strong></td><td>理解组织及其环境、相关方需求、QMS 范围、过程方法</td></tr><tr><td><strong>5</strong></td><td><strong>领导作用</strong></td><td>领导承诺、质量方针、角色与职责</td></tr><tr><td><strong>6</strong></td><td><strong>策划</strong></td><td>应对风险和机遇的措施、质量目标及其实施策划、变更策划</td></tr><tr><td><strong>7</strong></td><td><strong>支持</strong></td><td>资源、能力、意识、沟通、成文信息</td></tr><tr><td><strong>8</strong></td><td><strong>运行</strong></td><td>运行策划与控制、产品和服务要求、设计和开发、外部提供、生产和交付、不合格输出</td></tr><tr><td><strong>9</strong></td><td><strong>绩效评价</strong></td><td>监视、测量、分析和评价、内部审核、管理评审</td></tr><tr><td><strong>10</strong></td><td><strong>改进</strong></td><td>不符合与纠正措施、持续改进</td></tr></tbody></table><blockquote><p><strong>第 4–10 条是审核的重点条款</strong>，其中第 6 条（策划）和第 8 条（运行）是审核中发现问题最多的区域。</p></blockquote><h2 id="认证流程" tabindex="-1">认证流程 <a class="header-anchor" href="#认证流程" aria-label="Permalink to &quot;认证流程&quot;">​</a></h2><p>企业获得 ISO 9001 认证的一般流程：</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[1. 差距分析] --&gt; B[2. 体系建立与文件编写]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C[3. 体系运行与内部审核]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt; D[4. 管理评审]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; E[5. 选择认证机构]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F[6. 第一阶段审核&lt;br/&gt;文件审核 + 体系策划评估]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G[7. 整改第一阶段问题]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[8. 第二阶段审核&lt;br/&gt;现场全面审核]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    H --&gt; I{审核结论}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt;|通过| J[9. 颁发认证证书]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    I --&gt;|有条件通过| K[10. 整改后验证]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    K --&gt; J</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    J --&gt; L[11. 监督审核&lt;br/&gt;每年一次]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    L --&gt; M[12. 换证审核&lt;br/&gt;每三年一次]</span></span></code></pre></div><h3 id="认证周期示例" tabindex="-1">认证周期示例 <a class="header-anchor" href="#认证周期示例" aria-label="Permalink to &quot;认证周期示例&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>预估时间</th></tr></thead><tbody><tr><td>体系建立与运行</td><td>3–6 个月</td></tr><tr><td>内部审核与管理评审</td><td>1–2 个月</td></tr><tr><td>认证审核（两阶段）</td><td>1–2 个月</td></tr><tr><td><strong>总计</strong></td><td><strong>6–12 个月</strong></td></tr></tbody></table><h2 id="主要变化-iso-9001-2015-vs-iso-9001-2008" tabindex="-1">主要变化：ISO 9001:2015 vs ISO 9001:2008 <a class="header-anchor" href="#主要变化-iso-9001-2015-vs-iso-9001-2008" aria-label="Permalink to &quot;主要变化：ISO 9001:2015 vs ISO 9001:2008&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>ISO 9001:2008</th><th>ISO 9001:2015</th></tr></thead><tbody><tr><td>条款结构</td><td>8 个条款</td><td>10 个条款（HLS 架构）</td></tr><tr><td>预防措施</td><td>单独条款 (8.5.3)</td><td>融入基于风险的思维 (6.1)</td></tr><tr><td>成文信息</td><td>文件化程序 + 记录</td><td>成文信息（更灵活）</td></tr><tr><td>管理者代表</td><td>要求指定</td><td>不再强制要求</td></tr><tr><td>质量手册</td><td>要求编写</td><td>不再强制要求独立手册</td></tr></tbody></table><blockquote><p><strong>提示</strong>：ISO 9001:2015 强调灵活性和适应性，不再强制要求质量手册和文件化程序，而是让组织根据自身情况决定成文信息的范围。</p></blockquote><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./iatf-16949">IATF 16949 汽车行业质量管理体系</a></li><li><a href="./six-sigma">六西格玛方法论</a></li><li><a href="./lean-production">精益生产</a></li><li><a href="/certification/">CQE 认证备考</a></li></ul>`,26)])])}const k=s(d,[["render",r]]);export{c as __pageData,k as default};
